# ----------- PROCESS IMAGES -----------
for i in range(1, 601):

    filename = f"E{i:03d}.jpg"
    path = os.path.join(IMAGE_DIR, filename)

    if not os.path.exists(path):
        print(f"{filename} not found")
        continue

    img = Image.open(path).convert("RGB")
    draw = ImageDraw.Draw(img)

    # Select data
    index = (i - 1) % len(Dates)
    issue_date = Dates[index]
    percentage = Percentages[index]

    # Every 50 images change values
    batch = (i - 1) // 300

    if batch % 2 == 0:
        credits = 4
        course_code = "EDXPP150"
    else:
        credits = 6
        course_code = "EDXML220"

    # Draw text
    draw.text((CODE_X, CODE_Y),
              f"Course Code: {course_code}", fill=TEXT_COLOR, font=FONT)
    draw.text((CREDIT_X, CREDIT_Y),
              f"Credits: {credits}", fill=TEXT_COLOR, font=FONT)
    draw.text((PERCENT_X, PERCENT_Y),
              f"Percentage: {percentage}", fill=TEXT_COLOR, font=FONT)
    draw.text((DATE_X, DATE_Y),
              f"Issued On: {issue_date}", fill=TEXT_COLOR, font=FONT)

    save_path = os.path.join(OUTPUT_DIR, filename)
    img.save(save_path)

    print(f"Generated {filename}")

print("All certificates generated.")
